var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"시공간 수정의 후유증은 꽤나 다양해, 친구.","JPN":"時空間修正の後遺症は、かなり様々だ。","ENG":"Side effects of spacetime recalibration are quite diverse, my friend.","TWN":"修正時空會引起多種後遺症，朋友。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특히나 자네처럼 많이 겪은 경우에는...... 무슨 일이 일어날지 장담할 수 없어.","JPN":"特に君のように、色んなことがあった場合……何が起きるかわからない。","ENG":"And for someone who has done it multiple times like yourself, there's no telling what might happen.","TWN":"特別是像你這種經歷了很多次的情況……我無法保證會發生什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 자네의 길잡이로서, 이것 하나는 얘기해 줄 수 있겠군.","JPN":"だが、君のガイドとして、これだけは言える。","ENG":"But as your guide, I can tell you this.","TWN":"但作為你的領路人，我可以告訴你一點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈에서 다른 사람과 눈을 마주치게 되더라도 너무 놀라진 마. 그건 실제가 아니고, 그들의 추억을 잠시 관측하는 것 뿐이니까.","JPN":"夢の中で他の人と目が合っても、あまり驚くな。それは現実ではなく、彼らの思い出を少し観察するにすぎない。","ENG":"Don't be too surprised if you get to make eye contact with someone else. It's not real. You're observing their memories for a short period of time.","TWN":"在夢裡，即使與他人對上視線也不要太驚訝。因為那並不是現實，你只是在暫時觀看他們的回憶而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사람들의 행복했던 시절을 함께 돌아보는 것도...... 자네가 앞으로 걸을 길에 작은 위안 정도는 되겠지.","JPN":"だが、誰かの幸せだった時期を一緒に振り返るのも……これから君が歩むべき道の、小さな癒しにはなるだろう。","ENG":"But looking back at people's memories of their happy past could provide some comfort for your mind while walking the path you're on.","TWN":"不過，與他人一同觀看幸福的回憶……或許能在你前行的道路上，成為小小的慰藉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"좋아~ 감자칩도 에너지드링크도 준비 완료~","JPN":"よ～し、ポテチとエナジードリンク、準備完了～。","ENG":"Chips, check. Energy drink, check.","TWN":"好～薯片和能量飲料都準備好了～"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"자~ 오늘은 또 어떤 자신만만한 친구들을 골려 보실까?","JPN":"さてと～今日は、誰をからかおうかな？","ENG":"Now, which arrogant fools should I pick on today?","TWN":"嗯～今天該挑選哪位自信滿滿的朋友呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"어디 보자, 랭글리는 다시 찾아가 봐야 김빠지니까......","JPN":"どれどれ。ラングリーは、もうつまらないし……","ENG":"Let's see. Langley's out. There's no point doing it again.","TWN":"讓我看看，再找蘭利就太掃興了……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"좋았어. 오늘은 아껴 두고 있었던 관리국 데이터베이스에 한 번 도전해 보실까.","JPN":"よし。今日は、管理局のデータベースに挑戦しよう。","ENG":"Alright. It's going to be the Administration's database today. I've been saving it for a time like this.","TWN":"很好。今天就挑戰一下珍藏已久的管理局資料庫吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"보안이 꽤 철저하다지만...... 휘스턴 할머니네 뒤뜰 담장보다 넘기 어렵겠어?","JPN":"セキュリティが、かなりしっかりしてるって噂だけど……ヒューストンさんの裏庭の塀を越えるより簡単でしょ。","ENG":"They say they're well guarded, but I doubt it'd be harder than climbing over the fence of Mrs. Whiston's house.","TWN":"雖說保全系統非常完善……但不可能比惠斯頓奶奶家的圍牆還要難翻吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"자아, 사이버캣의 보안 교실~ 시작해 보실까~","JPN":"さあ、サイバーキャットのセキュリティ教室～始まり～","ENG":"Cyber Cat's IT Security 101 starts... now.","TWN":"好的，賽博貓的保全課堂~開始啦~"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"......응?","JPN":"……あれ？","ENG":"Huh?","TWN":"……嗯！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"뭐야, 선객이 있었잖아?","JPN":"先客がいたのね。","ENG":"There's already someone trying to break into the system.","TWN":"什麼，已經有人捷足先登了？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"에휴, 이렇게 자기 쳐들어왔다고 광고하는 녀석들 때문에 나까지 욕을 먹잖아.","JPN":"はあ、侵入しましたって自慢するやつらのせいで、アタシまで叩かれるじゃない。","ENG":"And this guy's clumsy as heck. It's these types of people that give everyone in the business a bad name.","TWN":"唉，就是因為這種侵入後還要到處宣傳的傢伙，害得我也要被罵。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"사이버캣은 횡단보도 건널 때 손 들고 다니는 모범시민~ 신고합니다~","JPN":"サイバーキャットは横断歩道を渡る時、手を上げて渡るいい子なので～通報するね～","ENG":"Cyber Cat is an exemplary citizen who never forgets to raise hands when crossing the road. I'm reporting you.","TWN":"賽博貓是一個過斑馬線時都會舉手示意的模範市民~特此申告~"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"슝~ 보안팀에 메시지 넣었고~","JPN":"は～い、セキュリティチームに、メッセージを送ったから～","ENG":"Swoosh! The message has been sent to the security team.","TWN":"咻～已經將資訊投給保全團隊了～"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"다섯, 넷, 셋……","JPN":"ご、よん、さん……","ENG":"Let's see... Five, four, three...","TWN":"五，四，三……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"둘......","JPN":"に……","ENG":"two...","TWN":"二……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"하나.","JPN":"いち。","ENG":"one.","TWN":"一。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"이런 빌어먹을! 남의 장사에 왜 참견질이야!","JPN":"ちくしょう！　なんで首を突っ込むんだ！","ENG":"What the hell! What are you doing, poking your nose in someone else's business?","TWN":"你真是討厭！為什麼要干擾別人的生意啊！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"다짜고짜 음성 채팅이라니 매너가 꽝이네. 중요한 일이면 메일로 말할 것이지.","JPN":"いきなり音声チャット？　マナー最悪だわ。大事な話ならメールを送りなさい。","ENG":"Hey, didn't anyone tell you to ask whether your recipient is available before starting a voice chat? I'm currently unavailable, so contact me via email if you have business with me.","TWN":"竟然上來就想要語聊，真沒有禮貌。如果有重要的事情，就該用郵件跟我說吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"그리고 난 감자칩 먹기 바빠서 무슨 일 때문에 그러는지 정말로 모르겠는걸?","JPN":"あと、アタシはポテチに夢中で、何のことかさっぱりなんだけど？","ENG":"Besides, I'm busy munching on my potato chips. I don't know what you're talking about.","TWN":"而且我剛才還忙著吃薯片，根本不知道發生了什麼呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"웃기지 마, 새파랗게 어린 꼬맹이 주제에......","JPN":"ふざけんな、このクソガキが……","ENG":"Don't even start with me, you little rascal.","TWN":"別搞笑了，你這乳臭未乾的小鬼頭……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"보안팀 직원 매수하느라 얼마가 들었는지 알아? 이건 의뢰라고!","JPN":"セキュリティチームの職員を買収するために、\\nいくら使ったと思ってるんだ？　これは依頼なんだ！","ENG":"Do you know how much it cost me to buy out that security staff? I have a client who's waiting for me!","TWN":"你知不知道請保全團隊要花多少錢？我說這是委託啊！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"어딘지 몰라도 사람 볼 줄 모르네. 너 같은 삼류 도둑 나부랭이나 고용하고.","JPN":"誰が依頼したのか知らないけど、見る目ないわね。あなたみたいに、三流泥棒を雇うなんて。","ENG":"Whoever it is that hired you should really broaden their resource pool. No one with a slightest knowledge of data security would hire a third-rate thief like you.","TWN":"雖然不知道委託人在哪，但他看人的眼光真差啊。居然會雇傭你這種三流的小人物、"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 너 지금 그 알량한 실력 믿고 까부나 본데......","JPN":"な、何だって？　お前、ただじゃおかない……","ENG":"W-what? Kid, don't get too confident with your petty skills. I—","TWN":"什，什麼？你現在是仗著自己那點三腳喵功夫就跟我在這囂張……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"아, 잠깐. 타임.","JPN":"あ、待って。タンマ。","ENG":"Ah, hold up. Wait a second.","TWN":"啊，等一下。暫停一下。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"내가 지금 네 컴퓨터를 살짝 들여다보는데, 아주 흥미로운 자료들을 발견한 것 같아.","JPN":"今あなたのパソコンを見てるんだけど、とても興味深い資料を見つけたわ。","ENG":"I'm looking at your hard drive now, and I think I've run across something very interesting.","TWN":"我進你電腦看了一下，裡面似乎有不少有趣的資料啊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L36_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"뭐......? 너, 너 어느새......! 침입당할 경로 따위 없을 텐데?!","JPN":"何……？　お、お前、いつの間に……？\\n侵入できる経路なんてないはずなのに！？","ENG":"What? W-when did you... How... I made sure I had the firewall running!","TWN":"什……？你，你什麼時候……！我記得應該沒有入侵的途徑啊？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"이게 뭘까? 내가 보기엔 그로니아 반군들이 받아 잡수신 뇌물 리스트 같은데?","JPN":"これ、何かな？　グロニア反軍が受け取った賄賂のリスト？","ENG":"Now what do we have here? If I'm correct, this is the list of Gronian rebels who took bribes.","TWN":"這會是什麼呢？我看看，這似乎是羅尼亞叛軍那邊收受的賄賂名單吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"아니면 파일명만 그렇고 나처럼 자라나는 어린아이가 보면 맴매 맞는 내용일까?","JPN":"あ、でも中身は違うかもしれないよね。子供が見ちゃいけない動画だったりして？","ENG":"Or, this is a randomly generated file name made up to fool a kid like me.","TWN":"還是說只有檔案名是那樣，裡面其實是我這種小朋友看了就會挨打的內容嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"어쩌나~ 무서워서 못 열어 보겠네~ 반군 아저씨들에게 신고하면 친절하게 처리해 주려나?","JPN":"やだ～怖くて開けられないわ～反乱軍のおじさんたちに通報すれば、処理してくれるかな？","ENG":"What do I do, what do I do? I'm too scared to open it. Should I let the rebels know about this first?","TWN":"天啊~我太害怕不敢打開啊~向叛軍叔叔們舉報的話，他們應該會好好處理吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"제...... 젠장! 그만둬! 그만둬! 그걸 빼돌렸다는 사실이 알려지면 난 죽은 목숨이야! 알아?!","JPN":"く……くそ！　やめろ！　やめてくれ！\\nそれを盗んだのがバレたら、俺は殺される！　本当だ！","ENG":"D-drat! Stop! Stop it! Just stop! I'll be dead the moment they notice I have it, you hear me?","TWN":"混……混蛋！停下！停下！如果那個被搶走我會沒命的！知道嘛？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"그럼 얌전히 발 빼. 관리국 데이터베이스는 사이버캣이 오늘의 놀이터로 정해 뒀거든.","JPN":"だったら、さっさと消えて。今日は管理局のデータベースが、サイバーキャットの遊び場なの。","ENG":"Then shut up and get lost. The Administration's database is Cyber Cat's playground today.","TWN":"那就乖乖離開這裡。賽博貓已經決定把管理局資料庫當做今天的遊樂場了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"내 영역에서 얼쩡거리면 어떻게 되는지 블랙 네트워크에서 온갖 얼치기들이 간증해 줬잖아?","JPN":"私の縄張りでうろつくとどうなるか、ブラックネットワークのやつらに聞いたでしょ？","ENG":"Have you learned nothing from the cases of those good-for-nothings on the Dark Network who chose to mess with me?","TWN":"在我的領域囂張會有怎樣的後果，駭客網路裡那些糊塗蟲不都告訴你了嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"싫으면 눈물 젖은 사과문 적다가 그나마 있는 커리어도 홀랑 날리시든지.","JPN":"嫌なら、あなたのしがないキャリア、ぶっ潰してあげるけど。","ENG":"I'll have you spend the rest of your life on the run writing petitions and apology letters if you keep provoking me.","TWN":"如果不想受到懲罰，就寫一封滿懷歉意的道歉信給我。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"큭......","JPN":"くっ……","ENG":"You...","TWN":"呃……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HACKER_NPC_NULL_NULL","text":{"KOREA":"빌어먹을, 너도 세상 무서운 줄 모르고 설치다 큰코다칠 줄 알아!","JPN":"ちくしょう、調子に乗りやがって！　お前、覚えてろよ！","ENG":"Gah! Remember, kid. You'll pay for this.","TWN":"混蛋，你這不知天高地厚的傢伙，等著瞧吧有你好看的！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"와. 두고 보자는 녀석 200 스택 적립.","JPN":"うわ、今時そんな台詞、言う人がいたんだ。","ENG":"Dude, get in line. There are about 200 others waiting for me to pay.","TWN":"哇。成就達成啦，第200說要讓我等著瞧的人。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"다들 레퍼토리가 이렇게 비슷비슷해서야...... 창의력이 없으니 꼬리를 잡히지.","JPN":"みんなレパートリーが似てるから、ダメなのよ……もっと、想像力を働かせなきゃ。","ENG":"Can you at least come up with something creative? Your lack of creativity is the reason you're getting caught.","TWN":"你們連劇本都一模一樣……就是因為這麼沒創意才會被抓住啊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"응? 메일이네?","JPN":"あれ？　メール？","ENG":"Hm? There's a new mail.","TWN":"嗯？來郵件了？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"반갑습니다, 사이버캣.","JPN":"はじめまして、サイバーキャット様。","ENG":"Nice to meet you, Cyber Cat.","TWN":"您好，賽博貓。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL"},{"id":"L3_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"수소문 끝에 어렵게 연락처를 구해서 감사 인사를 전합니다.","JPN":"あちこちのつてで連絡先を伺い、こうして感謝の気持ちをお伝えします。","ENG":"We looked everywhere for a way to reach out to you.","TWN":"經歷一番波折，終於找到了您的聯繫方式。首先，向您表示感謝。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"들리는 이야기로는 저희 측에서 귀중한 자료들이 유출될 위기를 당신 덕분에 여러 차례 넘겼다고 하더군요.","JPN":"聞いたところによると、弊社の機密が漏洩しかけたところを、何度も助けてくださったそうですね。","ENG":"It has come to our knowledge that you were the reason behind the several failed data theft attempts against our company.","TWN":"聽說您多次大發神威，挽救了我們的資料洩露危機。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"좀처럼 기회를 잡지 못하다가, 이번에 연락드리게 되었습니다.","JPN":"なかなか連絡を差し上げる機会がなかったのですが、この度こうして連絡をさせていただくことになりました。","ENG":"I'm glad that we finally have the opportunity to thank you properly.","TWN":"之前一直沒能找到機會，這次終於聯繫上您了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"후후후......","JPN":"フフフ……","ENG":"*Chuckle*","TWN":"呵呵呵……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"하여간 돈이나 밝히는 바보들은 이 맛을 모른다니까.","JPN":"お金に目が眩んだバカどもは、この楽しさを知らないのよね。","ENG":"Those money-hungry morons will never know what this feels like.","TWN":"也是，那些只想著掙錢的笨蛋一定不懂這種感覺。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_TOUCH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"자아, 에너지드링크도 한 병 비웠고 기지개도 켰으니까......","JPN":"さて。エナジードリンクも1缶飲んだし、ストレッチもしたから……","ENG":"Now, that's one energy drink down, and I did my stretching, so...","TWN":"既然能量飲料也喝完了，懶腰也伸完了……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"즐거운 인터넷 나들이를 다시 시작해 보실까?","JPN":"もう一度、楽しいネットサーフィンといきましょう。","ENG":"Let's get back to finding some fun stuff on the web.","TWN":"重新開始愉快的網上聊天吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};